var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"인류 통합 방위군 제1 방위선, 거점 기지","JPN":"人類統合防衛軍第1防衛線、拠点基地","ENG":"Base, United Humankind Defense Force's 1st Defense Line","TWN":"人類共同保衛軍第一防線基地","THA":"ฐานทัพ แนวป้องกันที่ 1 กองกำลังป้องกันมนุษยชาติ ","VTN":"Căn cứ, Phòng Tuyến thứ 1 của Lực Lượng Phòng Vệ Nhân Loại Thống Nhất","SCN":"人类综合防卫军第1防线，据点基地","DEU":"Basis, 1. Verteidigungslinie der Verteidigungsstreitkräfte der vereinigten Menschheit","FRA":"Base de la 1e ligne de défense des Forces de défense unies de l'humanité"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"제3차 아포리아 공략 작전","JPN":"第3次アポリア攻略作戦","ENG":"Operation Aporia, 3rd attempt","TWN":"第三波攻陷阿波利亞作戰","THA":"ปฏิบัติการอาโพเรียความพยายามครั้งที่ 3","VTN":"Chiến dịch Aporia, nỗ lực thứ 3","SCN":"第3次阿波利亚作战","DEU":"Operation „Aporia – Der 3. Versuch“","FRA":"3e tentative de l'opération Aporia"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"최종 결전이라는 말을 듣기는 했는데…….","JPN":"最終決戦とは聞いていたけど……","ENG":"I did hear that this was going to be the final battle...","TWN":"我聽說這就是最終決戰了……"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"모, 못 본 사이에 뭔가 많이 달라진 것 같은데, 소령?","JPN":"み、見ない間に何だかだいぶ変わったわね、少佐？","ENG":"B-but you seemed to have changed a lot, Major.","TWN":"一陣子不見，你變了不少呢，少校？"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"아이기스의 마스터 코드는 내 오른쪽 눈에 깃들어 있네.","JPN":"アイギスのマスターコードは私の右眼に組み込まれている。","ENG":"The master code of Aegis is embedded in my right eye.","TWN":"埃癸斯的管理代碼藏在我右眼裡。"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"오른쪽 눈?","JPN":"右眼？","ENG":"Your right eye?","TWN":"右眼？"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"고유 무장, <color=#ffd34c>글라우코피스</color>.","JPN":"固有武装、<color=#ffd34c>グラウコーピス</color>。","ENG":"Unique Gear, <color=#ffd34c>Glaukopis</color>.","TWN":"專屬裝備<color=#ffd34c>雅典娜</color>。"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"의안 형태의 이 고유 무장은 우리 같은 분석 능력자의 연산 출력을 극적으로 끌어올려주지.","JPN":"義眼の形状をしたこの武装は、我々のような分析能力者の演算能力を劇的に引き上げてくれる。","ENG":"This Unique Gear, in the form of an artificial eye, dramatically increases the calculation output of analytical abilities similar to our own.","TWN":"義眼形態的專屬裝備，可以極大化我們這類分析者的運算輸出。"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"또한 아이기스의 모든 시스템은 글라우코피스 사용자의 CRF에만 반응하도록 설계되어 있어.","JPN":"また、アイギスのすべてのシステムはグラウコーピス使用者のCRFにのみ反応するよう設計されている。","ENG":"Also, all systems of Aegis are designed to respond exclusively to the CRF of the Glaukopis user.","TWN":"埃癸斯的所有系統都設計成只會對雅典娜使用者的CRF做出反應。"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"역으로 말하면 고유 무장을 이식하는 순간, 자네는 살아있는 채로 아이기스의 일부가 되는 거야.","JPN":"逆に言えば、固有武装を移植した瞬間、君は生きたままアイギスの一部になるんだ。","ENG":"In other words, the moment you get this Unique Gear implanted, you will be a part of Aegis as long as you live.","TWN":"反過來說，專屬裝備移植成功的那瞬間，你只要活著，就一直是埃癸斯的一部分。"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"따라서 고유 무장을 인계받은 자네가 죽으면, 우리 세계의 유산은 분자단위로 사라져버리겠지.","JPN":"つまり、固有武装を引き継いだ君が死亡すれば、我々の世界の遺産は分子単位に分解され消滅してしまうということだな。","ENG":"Accordingly, if you die with the Unique Gear, all our legacy will be disintegrated at a molecular level.","TWN":"所以，如果繼承專屬裝備的你死去，我們世界的遺產就會徹底分解消失。"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"자네에게 그걸 짊어질 각오가 있다면, 이 눈 자네에게 넘겨주겠네.","JPN":"君にそれを背負う覚悟があるなら、この眼は君に渡そう。","ENG":"If you are determined to take this risk, I shall hand the eye over to you.","TWN":"如果你有覺悟承擔這份責任，我就把這隻眼睛交給你。"},"stage":{"bg":"EXILER_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"그래서 뭐가 어떻게 된 건데?","JPN":"それで、なにがどうなってるの？","ENG":"So, what's gonna happen?","TWN":"所以，到底是怎麼回事？"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"간단히 요약하면, 이 로스트 쉽과 함의 무기고를 사용할 수 있게 되었어요.","JPN":"簡単に言えば、このロストシップと船の武器庫を使えるようになりました。","ENG":"Simply put, we have gained access to this Lost Ship and its arsenal.","TWN":"簡單來說，這艘失落艦船和武器庫已經可以使用了。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"그게 정말이야? 이 함선의 프로텍트는 생전 처음 보는 패턴이었다고!","JPN":"それって本当？　この艦船のプロテクトは生まれて初めて見るパターンだったのよ！","ENG":"Really? But I've never seen a protection pattern like this ship's!","TWN":"真的嗎？這艘艦船的防禦模式我還是第一次見到！"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};